    }

    calcDerivative(hy: Matrix[], xs: Matrix, ys: Matrix): BackPropagationResult {
        let dw: Matrix[] = [], dy: Matrix[] = [];
        for (let l = this.hlayer - 1; l >= 0; l--) {
            let lastHy = hy[l - 1] ? hy[l - 1] : xs;
            let af = this.af(l);
